class HighchartsDataView(APIView):
    def get(self, request, *args, **kwargs):
        data = {
            "chart_type": "line",
            "categories": ["Jan", "Feb", "Mar", "Apr", "May"],
            "series": [
                {
                    "name": "Series 1",
                    "data": [29.9, 71.5, 106.4, 129.2, 144.0]
                },
                {
                    "name": "Series 2",
                    "data": [34.9, 68.5, 98.4, 124.2, 145.0]
                }
            ]
        }
        return Response(data)


